input.new_string:
source ~/.zoxide.nu
source ~/.cache/carapace/init.nu
source ~/.local/share/atuin/init.nu
# Optional: only load if generated (e.g. after `mise activate nu` / starship init)
if ($nu.home-path | path join '.cache' 'starship' 'init.nu' | path exists) {
    use ~/.cache/starship/init.nu
}
if ($nu.home-path | path join '.cache' 'mise' 'init.nu' | path exists) {
    use ~/.cache/mise/init.nu
}

